const r=".card-shell{display:grid;gap:.76rem;position:relative;border-radius:20px;border:1px solid var(--border);background:linear-gradient(164deg,rgba(255,255,255,.045),transparent 52%),var(--panel);box-shadow:var(--shadow-sm);padding:1.2rem}.card-shell.immersive{width:min(100%,760px);height:100%;min-height:100%;margin:0 auto;align-content:stretch;grid-template-rows:auto 1fr;gap:1rem;border-radius:22px;border:1px solid rgba(255,255,255,.12);background:radial-gradient(120% 120% at 100% -12%,rgba(255,47,109,.2),transparent 55%),radial-gradient(110% 120% at -10% 110%,rgba(125,85,255,.16),transparent 58%),#0d131feb;box-shadow:0 26px 44px -34px #000000e6;padding:1.12rem 1.14rem 1.2rem;overflow:hidden}.card-type{margin:0;font-size:.71rem;letter-spacing:.09em;text-transform:uppercase;font-weight:800;color:transparent;background:linear-gradient(90deg,var(--accent-1),var(--accent-2) 50%,var(--accent-4));-webkit-background-clip:text;background-clip:text}@media(max-width:700px){.card-shell.immersive{width:100%;border-radius:16px;padding:.92rem .88rem 1rem}}";export{r as s};
